using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Echoes a greeting for the given name.")]
    public static string Greet(
        [Description("The name to greet")] string name) =>
        $"Hello, {name}!";

    [McpServerTool, Description("Returns the current server time in UTC.")]
    public static string GetServerTime() =>
        DateTime.UtcNow.ToString("O");
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the application configuration as JSON.")]
    public static string GetAppConfig() =>
        JsonSerializer.Serialize(new
        {
            version = "1.0.0",
            environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            features = new { darkMode = true, analytics = false },
            maxRetries = 3
        }, new JsonSerializerOptions { WriteIndented = true });
}

